INSERT INTO public.province_contexts 
  (province, economic_sectors, opportunities_2030, social_context, narrative_hooks)
VALUES
('Aceh', ARRAY['pertanian','perikanan','pariwisata halal','minyak & gas'], 'Aceh berpotensi menjadi hub pariwisata halal internasional dan pusat ekonomi syariah di Indonesia barat, didukung otonomi khusus dan kedekatan dengan pasar Malaysia.', 'Masyarakat religius dengan identitas Islam yang kuat. Nilai komunitas dan keluarga besar. Pesantren sebagai institusi pendidikan utama.', ARRAY['ekonomi syariah','pariwisata halal','agribisnis','perikanan laut dalam']),
('Sumatera Utara', ARRAY['pertanian','manufaktur','pariwisata','perkebunan sawit & karet'], 'Medan sebagai kota terbesar ketiga Indonesia terus berkembang sebagai pusat bisnis regional Sumatera, dengan pertumbuhan startup dan industri kreatif yang signifikan.', 'Masyarakat multikultural: Batak, Melayu, Jawa, Tionghoa. Semangat wirausaha tinggi, terutama di komunitas Tionghoa dan Batak.', ARRAY['bisnis regional Sumatera','agribisnis modern','pariwisata Danau Toba','industri kreatif Medan']),
('Sumatera Barat', ARRAY['pariwisata','pertanian','UMKM','pendidikan'], 'Ranah Minang berpotensi besar di ekonomi kreatif berbasis budaya, kuliner halal bertaraf internasional, dan pendidikan Islam modern.', 'Budaya rantau mendorong mobilitas dan entrepreneurship. Nilai adat Minangkabau yang kuat berpadu dengan Islam. Masyarakat sangat menghargai pendidikan.', ARRAY['kuliner halal global','ekonomi kreatif Minang','pariwisata budaya','pendidikan Islam']),
('Riau', ARRAY['minyak & gas','perkebunan sawit','industri','perdagangan'], 'Riau dan Pekanbaru berkembang sebagai pusat industri hilir sawit dan gateway perdagangan ke Malaysia-Singapura, dengan potensi besar di sektor logistik dan fintech.', 'Masyarakat dengan pendapatan per kapita tinggi karena migas. Budaya Melayu yang religius. Mobilitas lintas batas dengan Malaysia cukup tinggi.', ARRAY['industri hilir sawit','perdagangan lintas batas','logistik regional','fintech Melayu']),
('Kepulauan Riau', ARRAY['manufaktur','pariwisata','perdagangan','teknologi'], 'Batam sebagai kawasan ekonomi khusus terus menarik investasi manufaktur teknologi dan menjadi jembatan ekonomi Indonesia-Singapura.', 'Masyarakat kosmopolit dengan pengaruh Singapura dan Malaysia kuat. Mobilitas kerja lintas negara lazim. Budaya kerja lebih urban dan modern.', ARRAY['manufaktur teknologi','kawasan ekonomi khusus','jasa keuangan','pariwisata Bintan']),
('Jambi', ARRAY['pertanian','perkebunan','pertambangan','perdagangan'], 'Jambi memiliki potensi besar di agribisnis modern dan ekowisata, dengan posisi strategis di jalur perdagangan Sumatera.', 'Masyarakat campuran Melayu Jambi, Jawa, dan Minangkabau. Kehidupan masih erat dengan alam dan pertanian. Komunitas religius yang hangat.', ARRAY['agribisnis modern','ekowisata','perdagangan komoditas','UMKM digital']),
('Sumatera Selatan', ARRAY['minyak & gas','batubara','pertanian','industri'], 'Palembang sebagai kota Sriwijaya modern berkembang di sektor industri pengolahan, logistik Sumatera, dan pariwisata sejarah-budaya.', 'Kebanggaan sejarah Sriwijaya kuat. Masyarakat heterogen dengan etnis Palembang, Jawa, Batak. Kuliner dan budaya lokal sangat kaya.', ARRAY['industri pengolahan','logistik Sumatera','pariwisata sejarah','UMKM pempek global']),
('Bangka Belitung', ARRAY['pariwisata','perikanan','timah','pertanian'], 'Bangka Belitung bergeser dari ekonomi timah ke pariwisata premium dan perikanan modern, dengan pantai-pantai eksotis bertaraf internasional.', 'Komunitas kecil dan erat. Etnis Tionghoa-Melayu yang harmonis. Masyarakat pesisir dengan keterikatan kuat pada laut.', ARRAY['pariwisata pantai premium','perikanan modern','ekonomi pasca-timah','UMKM kuliner laut']),
('Bengkulu', ARRAY['pertanian','perikanan','pariwisata','batubara'], 'Bengkulu memiliki potensi besar di agribisnis kopi dan rempah premium, serta ekowisata hutan tropis yang belum banyak tereksplor.', 'Masyarakat yang ramah dan terbuka. Kebanggaan terhadap sejarah perjuangan nasional. Komunitas pertanian yang kuat.', ARRAY['kopi dan rempah premium','ekowisata','pertanian organik','perikanan laut']),
('Lampung', ARRAY['pertanian','industri','perikanan','pariwisata'], 'Lampung sebagai pintu gerbang Sumatera-Jawa berkembang pesat di agribisnis modern, logistik, dan industri pengolahan hasil pertanian.', 'Masyarakat transmigran campuran dari berbagai suku. Semangat kerja keras dan adaptif. Komunitas pertanian yang sangat produktif.', ARRAY['agribisnis modern','logistik Sumatera-Jawa','industri pengolahan','kopi robusta premium']),
('DKI Jakarta', ARRAY['keuangan','teknologi','kreatif','perdagangan','jasa'], 'Jakarta tetap menjadi pusat ekonomi digital dan inovasi Indonesia, dengan ekosistem startup terbesar dan pasar kerja paling kompetitif di negeri ini.', 'Masyarakat urban kosmopolit. Kompetisi tinggi. Koneksi jaringan sangat bernilai. Gaya hidup modern dengan berbagai subkultur.', ARRAY['startup teknologi','keuangan & fintech','ekonomi kreatif','media & konten digital']),
('Banten', ARRAY['industri','perdagangan','pariwisata','pertanian'], 'Banten sebagai kawasan industri strategis dekat Jakarta terus berkembang di manufaktur teknologi, logistik, dan sektor jasa modern.', 'Masyarakat heterogen dengan tradisi Betawi-Sunda yang kuat. Dekat Jakarta tapi punya identitas lokal tersendiri. Komunitas pesantren yang besar.', ARRAY['kawasan industri','logistik','pariwisata pantai','ekonomi pesantren']),
('Jawa Barat', ARRAY['manufaktur','teknologi','pertanian','pendidikan','kreatif'], 'Jawa Barat dengan Bandung sebagai Silicon Valley Indonesia memiliki ekosistem teknologi dan industri kreatif terkuat di luar Jakarta, dengan backbone industri manufaktur yang solid.', 'Budaya Sunda yang halus dan artistik. Masyarakat terdidik dengan universitas top banyak di sini. Komunitas startup dan kreatif yang aktif.', ARRAY['teknologi & startup Bandung','industri kreatif','manufaktur modern','agribisnis Priangan']),
('Jawa Tengah', ARRAY['manufaktur','pertanian','pariwisata','UMKM','pendidikan'], 'Jawa Tengah dengan Semarang dan Solo berkembang sebagai pusat industri furnitur & tekstil global, pariwisata budaya, dan UMKM yang naik kelas digital.', 'Budaya Jawa yang halus, sabar, dan kolektif. Menghormati hirarki dan tradisi. Komunitas pengrajin dan UMKM yang sangat kuat.', ARRAY['furnitur & kerajinan global','batik dan tekstil','pariwisata Borobudur','UMKM digital']),
('DI Yogyakarta', ARRAY['pendidikan','pariwisata','kreatif','teknologi','UMKM'], 'Yogyakarta sebagai kota pelajar dan kota kreatif UNESCO terus menjadi magnet talenta muda Indonesia, dengan ekosistem ekonomi kreatif dan startup yang berkembang pesat.', 'Komunitas mahasiswa dan akademisi yang dominan. Toleransi dan keberagaman tinggi. Budaya ngayah dan gotong royong kuat.', ARRAY['ekonomi kreatif','edukasi & EdTech','pariwisata budaya','startup sosial']),
('Jawa Timur', ARRAY['industri','pertanian','perdagangan','teknologi','UMKM'], 'Jawa Timur dengan Surabaya sebagai kota terbesar kedua Indonesia adalah mesin ekonomi nasional dengan industri berat, perdagangan, dan ekosistem UMKM paling produktif di Indonesia.', 'Semangat arek Suroboyoan yang lugas dan kompetitif. Tradisi pesantren NU yang kuat. Etos kerja keras dan jiwa dagang yang tinggi.', ARRAY['industri manufaktur','perdagangan regional','UMKM naik kelas','teknologi Surabaya']),
('Bali', ARRAY['pariwisata','kreatif','pertanian','teknologi'], 'Bali sebagai destinasi dunia berkembang menjadi hub ekonomi kreatif, digital nomad, dan wellness global, membuka peluang besar di hospitality management dan industri kreatif.', 'Budaya Hindu Bali yang spiritual dan artistik sangat kuat. Komunitas sangat terikat dengan tradisi. Paparan internasional tinggi dari pariwisata.', ARRAY['hospitality & pariwisata global','ekonomi kreatif','wellness industry','digital nomad hub']),
('Nusa Tenggara Barat', ARRAY['pariwisata','pertanian','perikanan','pendidikan'], 'NTB dengan Lombok berkembang pesat sebagai destinasi pariwisata halal dunia dan hub pertanian organik premium, didukung semangat Islam yang kuat.', 'Masyarakat Sasak yang religius dan berbudi. Pariwisata membawa modernisasi namun nilai lokal tetap kuat. Komunitas pesantren yang besar.', ARRAY['pariwisata halal Lombok','pertanian organik','perikanan premium','ekonomi pesantren']),
('Nusa Tenggara Timur', ARRAY['pariwisata','pertanian','perikanan','peternakan'], 'NTT dengan Labuan Bajo berkembang sebagai destinasi ekowisata premium dunia, dengan potensi besar di pertanian organik dan perikanan laut dalam.', 'Komunitas Katolik yang kuat dengan nilai kekeluargaan tinggi. Masyarakat yang tangguh dan adaptif. Keterikatan dengan alam sangat kuat.', ARRAY['ekowisata premium Labuan Bajo','pertanian organik','perikanan laut dalam','tenun & kerajinan NTT']),
('Kalimantan Barat', ARRAY['perkebunan','pertambangan','perdagangan','pertanian'], 'Kalimantan Barat dengan Pontianak berkembang di agribisnis modern dan perdagangan lintas batas dengan Malaysia, serta logistik untuk hilirisasi industri.', 'Masyarakat multietnis: Dayak, Melayu, Tionghoa yang harmonis. Budaya sungai yang kuat. Komunitas lintas batas dengan Malaysia aktif.', ARRAY['agribisnis modern','perdagangan lintas batas','logistik','ekowisata Dayak']),
('Kalimantan Tengah', ARRAY['pertambangan','perkebunan','kehutanan','pertanian'], 'Kalimantan Tengah memiliki potensi besar di hilirisasi mineral, pertanian modern lahan gambut yang berkelanjutan, dan ekowisata orangutan.', 'Komunitas Dayak yang kuat dengan kearifan lokal tinggi. Masyarakat yang erat dengan hutan dan alam. Identitas budaya yang unik.', ARRAY['hilirisasi mineral','pertanian berkelanjutan','ekowisata','kehutanan modern']),
('Kalimantan Selatan', ARRAY['batubara','pertanian','perdagangan','industri'], 'Kalimantan Selatan dengan Banjarmasin berkembang di perdagangan regional Kalimantan, industri pengolahan, dan UMKM berbasis budaya Banjar.', 'Masyarakat Banjar yang religius dan berdagang. Tradisi Islam yang kuat. Komunitas pedagang yang aktif dan berjiwa wirausaha.', ARRAY['perdagangan regional','industri pengolahan','UMKM Banjar','intan dan kerajinan']),
('Kalimantan Timur', ARRAY['minyak & gas','batubara','industri','pertanian'], 'Kalimantan Timur sebagai lokasi Ibu Kota Nusantara (IKN) sedang dalam transformasi besar menjadi pusat pemerintahan dan smart city, membuka peluang karier masif di berbagai sektor.', 'Masyarakat urban yang dinamis. Percampuran budaya dari berbagai suku. Semangat pembangunan dan modernisasi yang tinggi karena IKN.', ARRAY['IKN dan smart city','konstruksi & infrastruktur','teknologi pemerintahan','industri hilirisasi']),
('Kalimantan Utara', ARRAY['kehutanan','perkebunan','pertambangan','perikanan'], 'Kalimantan Utara sebagai provinsi termuda dengan perbatasan Malaysia memiliki potensi di perdagangan lintas batas, kehutanan berkelanjutan, dan perikanan modern.', 'Komunitas kecil yang erat, campuran Tidung, Bulungan, dan pendatang. Kehidupan erat dengan alam dan perbatasan.', ARRAY['perdagangan perbatasan','kehutanan berkelanjutan','perikanan modern','ekowisata perbatasan']),
('Sulawesi Utara', ARRAY['pariwisata','perikanan','pertanian','industri'], 'Sulawesi Utara dengan Manado berkembang sebagai pintu gerbang ke Pasifik, hub pariwisata bahari internasional, dan pusat perdagangan Indonesia Timur.', 'Masyarakat Minahasa yang terbuka dan kosmopolit. Pengaruh Kristen Protestan kuat. Budaya kuliner yang berani dan unik.', ARRAY['pariwisata bahari Bunaken','gateway Pasifik','perikanan modern','agribisnis Minahasa']),
('Gorontalo', ARRAY['pertanian','perikanan','pariwisata','pendidikan'], 'Gorontalo berkembang di agribisnis jagung premium, perikanan modern, dan pariwisata alam yang mulai dikenal nasional.', 'Masyarakat religius dengan nilai adat Gorontalo yang kuat. Komunitas kecil yang erat. Semangat pendidikan yang tinggi.', ARRAY['agribisnis jagung','perikanan modern','pariwisata alam','pendidikan Islam']),
('Sulawesi Tengah', ARRAY['pertambangan','pertanian','perikanan','pariwisata'], 'Sulawesi Tengah dengan Palu berkembang di hilirisasi nikel, agribisnis kakao premium, dan ekowisata Togean yang bertaraf internasional.', 'Masyarakat campuran dengan banyak suku. Proses pemulihan pasca-bencana yang membentuk ketangguhan komunitas. Keterikatan dengan alam yang kuat.', ARRAY['hilirisasi nikel','kakao premium','ekowisata Togean','pertanian modern']),
('Sulawesi Barat', ARRAY['pertanian','perikanan','perkebunan','pertambangan'], 'Sulawesi Barat berkembang di agribisnis kakao dan kelapa sawit, perikanan, serta berpotensi menjadi penyangga ekonomi Sulawesi bagian barat.', 'Masyarakat Mandar yang berjiwa pelaut dan berdagang. Budaya maritim yang kuat. Komunitas yang adaptif dan mobile.', ARRAY['kakao dan sawit premium','perikanan Mandar','perdagangan regional','agribisnis']),
('Sulawesi Selatan', ARRAY['pertanian','industri','perdagangan','pariwisata','teknologi'], 'Sulawesi Selatan dengan Makassar sebagai kota terbesar Indonesia Timur adalah pusat ekonomi regional dengan ekosistem startup yang tumbuh cepat dan tradisi dagang Bugis yang kuat.', 'Semangat siri dan pesse komunitas Bugis-Makassar yang tinggi. Jiwa pelaut dan pedagang yang kuat. Ekosistem akademik dan startup yang berkembang.', ARRAY['perdagangan regional timur','startup Makassar','agribisnis modern','pariwisata Toraja']),
('Sulawesi Tenggara', ARRAY['pertambangan','perikanan','pertanian','pariwisata'], 'Sulawesi Tenggara berkembang di hilirisasi nikel dan aspal, perikanan modern, serta pariwisata bahari Wakatobi yang sudah dikenal dunia.', 'Masyarakat Tolaki, Muna, Buton yang berjiwa maritim. Nilai adat yang kuat. Komunitas yang bangga dengan kekayaan lautnya.', ARRAY['hilirisasi nikel','pariwisata Wakatobi','perikanan modern','aspal Buton']),
('Maluku', ARRAY['perikanan','pariwisata','pertanian','pertambangan'], 'Maluku dengan rempah-rempah bersejarahnya berkembang di perikanan laut dalam modern, pariwisata bahari premium, dan agribisnis rempah yang naik kelas global.', 'Komunitas Kristen dan Islam yang hidup berdampingan dengan harmoni. Budaya pela gandong (persaudaraan) yang unik. Keterikatan kuat dengan laut.', ARRAY['perikanan laut dalam','pariwisata bahari','rempah premium global','pela gandong economy']),
('Maluku Utara', ARRAY['pertambangan','perikanan','pertanian','pariwisata'], 'Maluku Utara dengan boom nikel dan kobalt menjadi salah satu wilayah dengan pertumbuhan ekonomi tertinggi Indonesia, membuka peluang besar di industri dan jasa pendukungnya.', 'Masyarakat dengan kebanggaan sejarah Kesultanan Ternate-Tidore. Islam yang kuat berpadu dengan budaya adat. Semangat membangun yang tinggi karena boom ekonomi.', ARRAY['hilirisasi nikel & kobalt','baterai EV','perikanan premium','pariwisata sejarah kesultanan']),
('Papua', ARRAY['pertambangan','perikanan','pertanian','pariwisata'], 'Papua dengan kekayaan alam luar biasa bertransisi menuju ekonomi yang lebih inklusif, dengan potensi besar di ekowisata, pertanian modern, dan hilirisasi mineral.', 'Masyarakat dengan ratusan suku dan bahasa. Nilai komunal dan adat yang sangat kuat. Perpaduan unik antara modernitas dan kearifan lokal.', ARRAY['ekowisata','pertanian modern','hilirisasi mineral','pendidikan inklusif']),
('Papua Barat', ARRAY['pariwisata','perikanan','pertanian','pertambangan'], 'Papua Barat dengan Raja Ampat sebagai destinasi bahari terbaik dunia memiliki potensi besar di pariwisata premium, perikanan berkelanjutan, dan ekonomi biru.', 'Komunitas adat yang menjaga alam dengan kearifan lokal. Nilai konservasi yang kuat. Pariwisata membawa kesempatan baru dengan tantangan tersendiri.', ARRAY['pariwisata Raja Ampat premium','ekonomi biru','perikanan berkelanjutan','konservasi']),
('Papua Barat Daya', ARRAY['perikanan','pertanian','pariwisata','pertambangan'], 'Papua Barat Daya sebagai provinsi baru membangun fondasi ekonominya di perikanan, pertanian, dan potensi pariwisata bahari yang belum banyak tereksplor.', 'Provinsi baru yang sedang membangun identitas dan infrastruktur. Komunitas adat yang kuat dengan potensi besar.', ARRAY['perikanan','pembangunan provinsi baru','pariwisata bahari','pertanian lokal']),
('Papua Tengah', ARRAY['pertambangan','pertanian','pendidikan','jasa'], 'Papua Tengah dengan Timika sebagai pusat operasi Freeport memiliki ekonomi yang sedang bertransisi menuju diversifikasi, dengan investasi besar di pendidikan dan infrastruktur.', 'Komunitas adat Amungme, Kamoro, dan suku-suku pegunungan. Pertambangan membawa perubahan cepat. Investasi pendidikan yang meningkat signifikan.', ARRAY['hilirisasi tambang','pendidikan & SDM','infrastruktur','pertanian pegunungan']),
('Papua Pegunungan', ARRAY['pertanian','pariwisata','pendidikan','kehutanan'], 'Papua Pegunungan dengan Wamena sebagai pusat Lembah Baliem memiliki potensi besar di agrowisata, pertanian pegunungan organik, dan ekowisata budaya yang autentik.', 'Komunitas Dani, Lani, Yali dengan budaya yang sangat kaya dan autentik. Kehidupan erat dengan alam pegunungan. Modernisasi datang bertahap.', ARRAY['ekowisata budaya Baliem','pertanian organik pegunungan','agrowisata','pendidikan inklusif']),
('Papua Selatan', ARRAY['pertanian','perikanan','pariwisata','kehutanan'], 'Papua Selatan dengan Merauke sebagai lumbung pangan nasional memiliki potensi besar di agribisnis modern skala besar dan ekowisata hutan-rawa yang unik.', 'Komunitas Malind-anim dan suku-suku pesisir selatan. Kehidupan erat dengan sagu dan rawa. Peran strategis sebagai perbatasan dengan Papua Nugini.', ARRAY['lumbung pangan nasional','agribisnis modern','ekowisata rawa','perbatasan PNG'])
